import React, { useState } from 'react';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';

function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);

  const { login } = useAuth();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await loginUser({ email, password });
      login(res.data.token, res.data.user);
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>
      {/* Left side - branding */}
      <div style={s.left}>
        <div style={s.brand}>
          <span style={s.owl}>🦉</span>
          <span style={s.brandName}>DevNest</span>
        </div>
        <h2 style={s.tagline}>Your coding journey,<br/>all in one place.</h2>
        <div style={s.features}>
          {['DSA Tracker', 'GitHub Analytics', 'AI Coding Mentor', 'Interview Readiness'].map(f => (
            <div key={f} style={s.featureItem}>
              <span style={s.dot}></span>
              <span style={s.featureText}>{f}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Right side - form */}
      <div style={s.right}>
        <div style={s.card}>
          <h2 style={s.title}>Welcome back</h2>
          <p style={s.subtitle}>Login to continue your journey</p>

          {error && (
            <div style={s.errorBox}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div style={s.field}>
              <label style={s.label}>Email</label>
              <input
                style={s.input}
                type="email"
                placeholder="shrey@gmail.com"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
              />
            </div>

            <div style={s.field}>
              <label style={s.label}>Password</label>
              <input
                style={s.input}
                type="password"
                placeholder="••••••••"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
            </div>

            <button
              type="submit"
              style={loading ? {...s.btn, opacity: 0.7} : s.btn}
              disabled={loading}
            >
              {loading ? 'Logging in...' : 'Login →'}
            </button>
          </form>

          <p style={s.bottomText}>
            Account nahi hai?{' '}
            <a href="/register" style={s.link}>Register karo</a>
          </p>
        </div>
      </div>
    </div>
  );
}

const s = {
  page: {
    display: 'flex',
    minHeight: '100vh',
    background: '#0d0d0d',
    fontFamily: "'Segoe UI', sans-serif",
  },
  left: {
    flex: 1,
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'center',
    padding: '60px',
    background: 'linear-gradient(135deg, #0d0d0d 0%, #111827 100%)',
    borderRight: '1px solid #1f1f1f',
  },
  brand: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    marginBottom: '40px',
  },
  owl: {
    fontSize: '42px',
  },
  brandName: {
    fontSize: '28px',
    fontWeight: '700',
    color: '#ffffff',
    letterSpacing: '-0.5px',
  },
  tagline: {
    fontSize: '32px',
    fontWeight: '600',
    color: '#ffffff',
    lineHeight: '1.4',
    marginBottom: '40px',
  },
  features: {
    display: 'flex',
    flexDirection: 'column',
    gap: '16px',
  },
  featureItem: {
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
  },
  dot: {
    width: '8px',
    height: '8px',
    borderRadius: '50%',
    background: '#22c55e',
    display: 'inline-block',
  },
  featureText: {
    color: '#9ca3af',
    fontSize: '15px',
  },
  right: {
    flex: 1,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '40px',
  },
  card: {
    width: '100%',
    maxWidth: '420px',
    background: '#111111',
    border: '1px solid #1f1f1f',
    borderRadius: '20px',
    padding: '48px 40px',
  },
  title: {
    color: '#ffffff',
    fontSize: '26px',
    fontWeight: '600',
    marginBottom: '8px',
  },
  subtitle: {
    color: '#6b7280',
    fontSize: '14px',
    marginBottom: '32px',
  },
  errorBox: {
    background: '#1f0f0f',
    border: '1px solid #3f1f1f',
    borderRadius: '10px',
    padding: '12px 16px',
    color: '#ef4444',
    fontSize: '13px',
    marginBottom: '20px',
  },
  field: {
    marginBottom: '20px',
  },
  label: {
    display: 'block',
    color: '#9ca3af',
    fontSize: '13px',
    marginBottom: '8px',
    fontWeight: '500',
  },
  input: {
    width: '100%',
    padding: '13px 16px',
    background: '#0d0d0d',
    border: '1px solid #2a2a2a',
    borderRadius: '10px',
    color: '#ffffff',
    fontSize: '14px',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'border 0.2s',
  },
  btn: {
    width: '100%',
    padding: '14px',
    background: '#22c55e',
    border: 'none',
    borderRadius: '10px',
    color: '#000000',
    fontSize: '15px',
    fontWeight: '600',
    cursor: 'pointer',
    marginTop: '8px',
    letterSpacing: '0.3px',
  },
  bottomText: {
    textAlign: 'center',
    color: '#6b7280',
    fontSize: '13px',
    marginTop: '24px',
  },
  link: {
    color: '#22c55e',
    textDecoration: 'none',
    fontWeight: '500',
  }
};

export default Login;
